/* ── sceau d'angle : coin plié crème + FLEUR DE LYS dorée (motif image 2) ── */
function Seal({ color = C.gold500, size = 46 }) {
  return (
    <span className="seal" aria-hidden="true" style={{ position: "absolute", top: 0, right: 0, width: size, height: size, overflow: "hidden", borderTopRightRadius: 18, pointerEvents: "none" }}>
      <svg width={size} height={size} viewBox="0 0 46 46" style={{ display: "block" }}>
        {/* coin plié teinté */}
        <path d="M46 0 L46 46 L0 0 Z" fill={C.goldSoft} />
        {/* fleur de lys stylisée */}
        <g fill={color} transform="translate(26,9) scale(0.85)">
          <path d="M6 0 C8 3 8 6 6 9 C4 6 4 3 6 0 Z" />
          <path d="M6 8 C2 7 0 9 0.6 13 C1.4 11 3 10.5 5 11.4 C3.4 12.6 3 14 4 15.6 L6 13.2 L8 15.6 C9 14 8.6 12.6 7 11.4 C9 10.5 10.6 11 11.4 13 C12 9 10 7 6 8 Z" />
          <rect x="5.1" y="9" width="1.8" height="8" rx="0.6" />
          <rect x="2.4" y="12.2" width="7.2" height="1.6" rx="0.6" />
        </g>
      </svg>
    </span>
  );
}

function useReveal() {
  const ref = useRef(null);
  const [shown, setShown] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setShown(true); io.disconnect(); } }, { threshold: 0.15 });
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return [ref, shown];
}

